args.sparql:
SELECT ?person ?label WHERE {
  ?person wdt:P324 ?office;
    p:P324 ?statement.
  ?statement pq:P580 ?start;
    ps:P324 ?office.
  ?office wdt:P17 wd:Q16;
         wdt:P31 wd:Q2317188.
  ?person rdfs:label ?label.
  FILTER (LANG(?label) = 'en').
}
ORDER BY ?start
LIMIT 1
OFFSET 10

